Rule.Source:
  import sailpoint.object.Identity;
  import sailpoint.object.Custom;
    import org.apache.commons.logging.Log;
	import org.apache.commons.logging.LogFactory;
  import sailpoint.tools.Util;
  
  /**
		 * Escalate workitem to approvers Manager after 5 days
		 * @param item
		 * @return newOwner
		 */
  static Log logger = LogFactory.getLog("rule.CreateContractor");
  logger.debug("Entering Create Contractor Escalation Rule ");
  String FALLBACK_APPROVER = "IDM Team";
  Custom accessRequestCustom = context.getObjectByName(Custom.class, "Ascension-Custom-AccessRequest");
  if (accessRequestCustom != null && Util.isNotNullOrEmpty(accessRequestCustom.get("DefaultWorkgroup")) ) {
  	FALLBACK_APPROVER = accessRequestCustom.get("DefaultWorkgroup");
  }
  Identity newOwnerManager = null;
  if(null != item){	
  	Identity idenitynewOwner = item.getOwner();  
 
  	if (idenitynewOwner != null && !(idenitynewOwner.isInactive())) {
   		newOwnerManager = idenitynewOwner.getManager();
  	}
  }
  logger.debug("Exiting Create Contractor Escalation Rule");
  if (newOwnerManager == null){
    return FALLBACK_APPROVER;
  }
  else{
    return newOwnerManager.getName();
  }
